import os
import sys
import base64
from flask import Flask

app = Flask(__name__)

# كود تطبيق الـ Streamlit (app.py) الخاص بك كاملاً ومشفراً 100% لحمايته من التداخل واقتطاع النصوص
STREAMLIT_BASE64 = " 📄 Inline PDF (ZSl9IikKICAgICAgICAgICAgaWYgc3Quc2Vzc2lvbl9zdGF0ZS5taW5kbWFwX2NvZGU6CiAgICAgICAgICAgICAgICBzdC5tYXJrZG93bigi#####ID8gTm9kZSBUb3BvbG9neSBFbmdpbmUiKQogICAgICAgICAgICAgICAgaHRtbF9jb2RlID0gZiIiIgo8ZGl2IGNsYXNzPSJtZXJtYWlkIiBzdHlsZT0iZGlzcGxheTogZmxleDsganVzdGlmeS1jb250ZW50OiBjZW50ZXI7IGFsaWduLWl0ZW1zOiBjZW50ZXI7Ij4Ke3N0LnNlc3Npb25fc3RhdGUubWluZG1hcF9jb2德"

# فك التشفير التلقائي وتمريره لـ stlite دون المساس بأي حرف أو سياق
DECODED_CODE = base64.b64decode(STREAMLIT_BASE64.encode('utf-8')).decode('utf-8')

@app.route('/')
def index():
    return f"""
    <!DOCTYPE html>
    <html>
    <head>
      <meta charset="UTF-8">
      <meta http-equiv="X-UA-Compatible" content="IE=edge">
      <meta name="viewport" content="width=device-width, initial-scale=1, shrink-to-fit=no">
      <title>Contextify AI - Workspace</title>
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@stlite/mountable@0.54.0/build/stlite.css">
    </head>
    <body>
      <div id="root"></div>
      <script src="https://cdn.jsdelivr.net/npm/@stlite/mountable@0.54.0/build/stlite.js"></script>
      <script>
        stlite.mount({{
          requirements: ["requests", "pypdf"],
          entrypoint: "app.py",
          files: {{
            "app.py": {repr(DECODED_CODE)}
          }},
          streamlitConfig: {{
            "server.headless": true,
            "theme.primaryColor": "#0f172a"
          }}
        }}, document.getElementById("root"));
      </script>
    </body>
    </html>
    """

# إتاحة وتصدير المتغيرات التي يبحث عنها فحص المنصة لتجنب خطأ الـ Entrypoint
application = app
handler = app
